import{_ as e,c as t,o,a4 as i}from"./chunks/framework.BmdFiWrL.js";const m=JSON.parse('{"title":"Service Monitoring","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/services.md","filePath":"en_US/guide/services.md","lastUpdated":1780405010000}'),r={name:"en_US/guide/services.md"},n=i('<h1 id="service-monitoring" tabindex="-1">Service Monitoring <a class="header-anchor" href="#service-monitoring" aria-label="Permalink to &quot;Service Monitoring&quot;">​</a></h1><p><strong>The service area is used to configure Agents to monitor external websites or servers.</strong> After setting up service monitors, you can click the <strong><code>Services</code></strong> icon on the homepage to view availability monitoring results from the past 30 days.</p><hr><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><h3 id="add-a-new-service-monitor" tabindex="-1">Add a New Service Monitor <a class="header-anchor" href="#add-a-new-service-monitor" aria-label="Permalink to &quot;Add a New Service Monitor&quot;">​</a></h3><p>To add a new service monitor, follow these steps:</p><ol><li><p><strong>Open the admin frontend</strong> Go to the <strong><code>Services</code></strong> page and click the <strong><code>+</code></strong> button to add a new service monitor.</p></li><li><p><strong>Configure parameters</strong> Set the following parameters when adding the monitor:</p><ul><li><strong>Name</strong>: A custom name for this service.</li><li><strong>Target</strong>: Set the target according to the monitor type: <ul><li><code>HTTP GET</code>: Enter the full URL, including <code>http://</code> or <code>https://</code>, for example: <code>https://example.com</code>. <strong>Note</strong>: If the target URL uses <code>https://</code>, Nezha Monitor also monitors the SSL certificate of that URL. Certificate expiration or changes will trigger notifications.</li><li><code>ICMP Ping</code>: Enter a domain name or IP address without a port, for example: <code>1.1.1.1</code> or <code>example.com</code>.</li><li><code>TCPing</code>: Enter a domain name or IP address with a port, for example: <code>1.1.1.1:80</code> or <code>example.com:22</code>.</li></ul></li><li><strong>Type</strong>: Select the monitor type: <code>HTTP GET</code>, <code>ICMP Ping</code>, or <code>TCPing</code>.</li><li><strong>Hidden from Visitors</strong>: Whether to hide this monitor from guests. This is a privacy option. Visible by default; when checked, guests cannot see this service monitor, matching the server&#39;s &quot;Hidden from Visitors&quot; behavior.</li><li><strong>Interval</strong>: Monitoring interval in seconds.</li><li><strong>Sort</strong>: Display order for service monitors. Higher values are shown first.</li><li><strong>Cover</strong>: Select a rule to decide which Agents request the target.</li><li><strong>Specific Servers</strong>: Specify Agents within the selected cover rule.</li><li><strong>Notification Group ID</strong>: Select notification methods configured on the <strong><code>Notifications</code></strong> page. See <a href="/en_US/guide/notifications.html#flexible-notification-methods">Notification Method Configuration</a>.</li><li><strong>Enable Failure Notification</strong>: Optionally receive notifications when the target fails. Disabled by default.</li></ul></li><li><p><strong>Submit the monitor</strong> Click <strong><code>Submit</code></strong> to save the configuration, then wait a moment and return to the homepage to view monitoring results.</p></li></ol><hr><h2 id="delay-change-notifications" tabindex="-1">Delay Change Notifications <a class="header-anchor" href="#delay-change-notifications" aria-label="Permalink to &quot;Delay Change Notifications&quot;">​</a></h2><p>Nezha Monitor collects and monitors latency between Agents and target servers. When latency changes significantly, it can send notifications to help monitor route status.</p><ul><li><strong>Enable Delay Notification</strong>: After enabling this option, notifications are sent when latency exceeds the configured range, either higher than <code>Maximum Latency</code> or lower than <code>Minimum Latency</code>.</li></ul><hr><h2 id="trigger-tasks-on-notification" tabindex="-1">Trigger Tasks on Notification <a class="header-anchor" href="#trigger-tasks-on-notification" aria-label="Permalink to &quot;Trigger Tasks on Notification&quot;">​</a></h2><p>If you need to run a specific task when a service monitor triggers a notification:</p><ol><li>Check <strong><code>Enable Trigger Task</code></strong>.</li><li>Configure: <ul><li><strong>Task triggered by alert</strong>: Select the task to run when the alert is triggered.</li><li><strong>Task triggered after recovery</strong>: Select the task to run after the service recovers.</li></ul></li></ol><p>Set up the task configuration on the Tasks page before using this feature.</p><hr><h2 id="network-latency-charts" tabindex="-1">Network Latency Charts <a class="header-anchor" href="#network-latency-charts" aria-label="Permalink to &quot;Network Latency Charts&quot;">​</a></h2><p>For <code>TCPing</code> and <code>ICMP-Ping</code> monitors, the Dashboard automatically generates network latency charts:</p><ul><li>Open the corresponding server detail page and switch to the <strong><code>Network</code></strong> tab.</li><li>View historical network latency trends based on real-time latency statistics from the Agent to the target server.</li><li>You can select 1 day, 7 days, or 30 days. Guests can only view 1 day of data; 7-day and 30-day data require login.</li><li>If the same server participates in multiple monitors, you can select multiple monitors for comparison. When only one monitor is selected, the chart shows both latency and packet loss.</li><li>Network charts support peak clipping to reduce the impact of sudden spikes on chart readability. You can enable it by default in frontend custom code with <code>window.ForcePeakCutEnabled = true</code>.</li></ul><hr><h2 id="user-frontend-display" tabindex="-1">User Frontend Display <a class="header-anchor" href="#user-frontend-display" aria-label="Permalink to &quot;User Frontend Display&quot;">​</a></h2><p>The service monitoring panel on the user frontend homepage displays public services&#39; availability and latency overview for the past 30 days. Users can click the service button on the homepage to expand or collapse this panel, or set <code>window.ForceShowServices = true</code> in <a href="/en_US/guide/settings.html#custom-code">Custom Code</a> to expand it by default.</p><p>If the server returns cycle traffic statistics, the homepage service panel also displays cycle traffic cards. Service monitors are displayed by the <strong>Sort</strong> field in their configuration; higher values are shown first.</p><p>When there is no service data to display, the user frontend shows an empty-state message. This usually means service monitoring has not been enabled, services are not set to public display, or the currently selected server group has no related service monitoring data.</p><hr><h2 id="manage-monitors" tabindex="-1">Manage Monitors <a class="header-anchor" href="#manage-monitors" aria-label="Permalink to &quot;Manage Monitors&quot;">​</a></h2><p>To edit or delete an existing service monitor:</p><ol><li>Open the <strong><code>Services</code></strong> page in the admin frontend.</li><li>Find the target monitor configuration.</li><li>Click the edit or delete icon on the right to modify or remove it.</li></ol>',29),a=[n];function s(c,l,d,h,g,p){return o(),t("div",null,a)}const f=e(r,[["render",s]]);export{m as __pageData,f as default};
